require('dotenv').config();
const { ethers } = require('ethers');

// --- Configuration ---
const PRIVATE_KEY = process.env.PRIVATE_KEY;
const ETHEREUM_NODE_URL = process.env.ETHEREUM_NODE_URL;

if (!PRIVATE_KEY || !ETHEREUM_NODE_URL) {
    console.error("Error: Please set PRIVATE_KEY and ETHEREUM_NODE_URL in your .env file.");
    process.exit(1);
}

// --- Ethers.js Setup ---
const provider = new ethers.JsonRpcProvider(ETHEREUM_NODE_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

console.log(`Wallet Address: ${wallet.address}`);
console.log(`Connected to Ethereum Node: ${ETHEREUM_NODE_URL}`);

// --- Functions to Interact with Ethereum ---

/**
 * Sends a specified amount of ETH to a recipient address.
 * @param {string} recipientAddress The Ethereum address to send ETH to.
 * @param {string} amountInEth The amount of ETH to send (as a string, e.g., "0.01").
 * @returns {Promise<ethers.TransactionReceipt>} The transaction receipt.
 */
async function sendEth(recipientAddress, amountInEth) {
    console.log(`Attempting to send ${amountInEth} ETH to ${recipientAddress}...`);
    try {
        const tx = await wallet.sendTransaction({
            to: recipientAddress,
            value: ethers.parseEther(amountInEth), // Converts ETH string to Wei BigInt
        });

        console.log(`Transaction sent! Hash: ${tx.hash}`);
        const receipt = await tx.wait(); // Wait for transaction to be mined
        console.log('Transaction confirmed!');
        console.log('Receipt:', receipt);
        return receipt;
    } catch (error) {
        console.error('Error sending ETH:', error.message);
        throw error;
    }
}

/**
 * Calls a read-only (view/pure) method on a smart contract.
 * @param {string} contractAddress The address of the smart contract.
 * @param {ethers.Interface | string | any[]} contractAbi The ABI of the smart contract.
 * @param {string} methodName The name of the method to call.
 * @param {any[]} args An array of arguments for the method.
 * @returns {Promise<any>} The result of the contract call.
 */
async function callContractViewMethod(contractAddress, contractAbi, methodName, args = []) {
    console.log(`Calling view method '${methodName}' on contract ${contractAddress}...`);
    try {
        const contract = new ethers.Contract(contractAddress, contractAbi, provider);
        const result = await contract[methodName](...args);
        console.log(`Method '${methodName}' result:`, result);
        return result;
    } catch (error) {
        console.error(`Error calling view method '${methodName}':`, error.message);
        throw error;
    }
}

/**
 * Sends a transaction to a smart contract to execute a state-changing method.
 * @param {string} contractAddress The address of the smart contract.
 * @param {ethers.Interface | string | any[]} contractAbi The ABI of the smart contract.
 * @param {string} methodName The name of the method to call.
 * @param {any[]} args An array of arguments for the method.
 * @param {string} valueInEth Optional. The amount of ETH to send with the transaction (for payable functions).
 * @returns {Promise<ethers.TransactionReceipt>} The transaction receipt.
 */
async function sendContractTransaction(contractAddress, contractAbi, methodName, args = [], valueInEth = "0") {
    console.log(`Sending transaction for method '${methodName}' on contract ${contractAddress}...`);
    try {
        const contract = new ethers.Contract(contractAddress, contractAbi, wallet); // Use wallet for signing
        const txOptions = {
            value: ethers.parseEther(valueInEth), // Amount of ETH to send with the transaction
        };

        const tx = await contract[methodName](...args, txOptions);
        console.log(`Transaction sent! Hash: ${tx.hash}`);
        const receipt = await tx.wait(); // Wait for transaction to be mined
        console.log('Transaction confirmed!');
        console.log('Receipt:', receipt);
        return receipt;
    } catch (error) {
        console.error(`Error sending transaction for method '${methodName}':`, error.message);
        throw error;
    }
}

